import { expect, test, suite } from "vitest";
import { process } from "./clean.ts";

expect.addSnapshotSerializer({
  test: (val) => val && val instanceof File,
  serialize: (file: File) => `File ${file.name}: ${file.size} bytes`,
});

suite("basic tests", () => {
  test("sanity check", () => {
    expect(process("<div><p>Hello world!</p></div>")).toMatchInlineSnapshot(`
    {
      "files": [],
      "html": "<p>Hello world!</p>",
    }
  `);
  });

  test("base 64 image extraction", () => {
    expect(
      process(
        '<div><img src="data:image/png;base64,iVBORw0KGgoAAAANSUhEUgAAAAEAAAABCAIAAACQd1PeAAAAD0lEQVR4AQEEAPv/AP9EAAOJAUSHQ2JJAAAAAElFTkSuQmCC" alt="Red dot"/><img src="http://example.com/img" alt="Forest"/></div>',
      ),
    ).toMatchInlineSnapshot(`
      {
        "files": [
          File ￼_0_: 72 bytes,
        ],
        "html": "<p><img src="￼_0_"></p>",
      }
    `);
  });

  test("basic html cleanup", () => {
    expect(
      process(
        `<div>
          <a href="https://example.com"><strong> Click here </strong></a>to visit
          <span style="font-weight: 700;">our site</span>!
        </div>`,
      ),
    ).toMatchInlineSnapshot(`
      {
        "files": [],
        "html": "<p><a href="https://example.com"><strong>Click here</strong></a> to visit <strong>our site</strong>!</p>",
      }
    `);
  });

  test("divpocalypse", () => {
    expect(process(`<div><div><div><p>Hello</p></div></div></div>`)).toMatchInlineSnapshot(`
    {
      "files": [],
      "html": "<p>Hello</p>",
    }
  `);
  });

  test("empty elements", () => {
    expect(process(`<div><p>Hello</p><p> </p><a href="http://example.com"> </a></div>`))
      .toMatchInlineSnapshot(`
      {
        "files": [],
        "html": "<p>Hello</p>",
      }
    `);
  });

  test("inline elements", () => {
    expect(process(`<em>Look at me</em><code>I'm a developer</code>`)).toMatchInlineSnapshot(`
      {
        "files": [],
        "html": "<p><em>Look at me</em><code>I'm a developer</code></p>",
      }
    `);
  });

  test("remove silent html elements", () => {
    expect(process(`<!DOCTYPE html><p>  <!-- comment -->  </p>`)).toMatchInlineSnapshot(`
      {
        "files": [],
        "html": "",
      }
    `);
  });

  test("bold collapsing", () => {
    expect(
      process(`<b>Bold <strong>and <span style="font-weigth: bold">strong</span></strong></b>`),
    ).toMatchInlineSnapshot(`
      {
        "files": [],
        "html": "<p><strong>Bold and strong</strong></p>",
      }
    `);
  });

  test("line breaks", () => {
    expect(
      process(
        `<p>Hello<br>World<br/><br></p><br><p>Foo<br><br><br>Bar</p><p><br><br />Trim new lines<br><br></p>`,
      ),
    ).toMatchInlineSnapshot(`
      {
        "files": [],
        "html": "<p>Hello<br>World</p><p>Foo</p><p>Bar</p><p>Trim new lines</p>",
      }
    `);
  });

  test("de-nest line breaks", () => {
    expect(process(` <p> <em> Foo </em> <em> <br> </em> <em> Bar </em> </p> `))
      .toMatchInlineSnapshot(`
      {
        "files": [],
        "html": "<p><em>Foo</em> <br> <em>Bar</em></p>",
      }
    `);
  });

  test("fix whitespace", () => {
    expect(
      process(
        `<p><a>Click </a>me</p><blockquote><p><strong> </strong></p></blockquote><p> Foo </p>`,
      ),
    ).toMatchInlineSnapshot(`
      {
        "files": [],
        "html": "<p><a>Click</a> me</p><p>Foo</p>",
      }
    `);
  });

  test("repair html", () => {
    expect(
      process(`
      <p><strong>Bold <em>and italic</strong></em></p>
      <p><h1>Heading inside p</h1></p>
      <ul>List inside p</ul>
    `),
    ).toMatchInlineSnapshot(`
      {
        "files": [],
        "html": "<p><strong>Bold <em>and italic</em></strong></p><h1>Heading inside p</h1><ul><li>List inside p</li></ul>",
      }
    `);
  });
});

